  "الخوف من الله عبادة فلا يجوز صرفه لغيره": "الْخَوْف مِن اللَّه عِبَادَة فلَا يَجُوز صَرْفُهُ لِغَيَّرَهُ\u0001",
  "الخوف التعبدي لا يصرف إلا لله": "الْخَوْف التَّعَبُّدِيُّ لَا يَصْرِفُ إِلَّا لِلَّه\u0001",
  "محبة النبي ﷺ واجبة وتابعة لمحبة الله": "مَحَبَّةُ النَّبِيّ ﷺ وَاجِبَةً وَتَابِعَةً لِمَحَبَّةَ اللَّه\u0001",
  "يجب أن يكون الله ورسوله أحب إلينا مما سواهما": "يَجِبُ أَن يَكْوُنَّ اللَّه وَرَسُولِهِ أَحُبٌّ إِلَيْنَا مِمَّا سِوَاهُمَا\u0001",
  "التشاؤم بالأيام والأرقام من التطير": "التَّشَاؤُمُ بِالْأَيَّامِ وَالْأَرْقَامِ مِن التَّطَيُّر\u0001",
  "والطيرة شرك": "وَالطَّيْرَةُ شِرْك\u0001",
  "ما حكم إتيان الكهان والعرافين": "مَا حُكْم إِتْيَانِ الْكُهَّانِ وَالْعَرَّافِينَ ؟",
  "من أتى عرافا فسأله عن شيء لم تقبل له صلاة أربعين ليلة": "مَنٌّ أَتَى عَرَّافًا فَسَأَلَهُ عَن شَيْءٍ لَم تَقْبَلُ لَه صَلَاة أَرْبَعِينَ لَيْلَةً\u0001",
