  "تعلم النجوم لمعرفة الفصول والأوقات جائز": "تَعْلَمُ النُّجُوم لِمَعْرِفَةَ الْفُصُولِ وَالْأَوْقَاتِ جَائِز\u0001",
  "أما الاعتقاد بتأثيرها فحرام": "أُمَّا الْاِعْتِقَادِ بِتَأْثِيرِهَا فَحَرَامٍ\u0001",
  "ما حكم النشرة حل السحر بالسحر": "مَا حُكْم النُّشْرَة ( حَلَّ السِّحْر بِالسَّحَرِ )؟",
  "النشرة الجاهلية محرمة": "النُّشْرَة الْجَاهِلِيَّةُ مُحَرَّمَةٌ\u0001",
  "حرام لأنها من عمل الشيطان": "حَرَام لأَنّهَا مِن عَمَل الشَّيْطَانِ",
  "مستحبة": "مُسْتَحَبَّةٌ",
  "حل السحر بالرقية الشرعية جائز": "حَلُّ السِّحْر بِالرُّقِيَّةِ الشَّرْعِيَّةَ جَائِز\u0001",
  "أما حله بسحر مثله فحرام": "أُمَّا حَلِّهِ بِسَحَرِ مِثْلهُ فَحَرَامٌ\u0001",
  "الشفاعة التي نفاها القرآن هي": "الشَّفَاعَةُ الَّتِي نَفَاهَا الْقُرْآن هِي\u0001",
  "الشفاعة التي فيها شرك منتفية يوم القيامة": "الشَّفَاعَةُ الَّتِي فِيهَا شِرْك منتفية يَوْمَ الْقِيَامَةِ\u0001",
